func (s *syncSession) replicateCanBootstrap(desiredRefs map[plumbing.ReferenceName]planner.DesiredRef) bool {
	for targetRef := range desiredRefs {
		if !s.target.refMap[targetRef].IsZero() {
			return false
		}
	}
	if !s.cfg.Prune {
		return true
	}
